DROP TABLE IF EXISTS `owner_user`;
CREATE TABLE `owner_user`(owner_user_id int(11) NOT NULL AUTO_INCREMENT COMMENT '车主用户ID',
`owners_name` varchar(64) comment '车主姓名',
`owners_gender` varchar(64) comment '车主性别',
`contact_number` varchar(16) NOT NULL UNIQUE comment '联系号码',
`driving_license` varchar(255) comment '驾驶证件',
`member_level` varchar(64) comment '会员等级',
`accumulate_points` double(8,2) DEFAULT 0 comment '积攒积分',
`examine_state` varchar(16) DEFAULT '已通过' NOT NULL comment '审核状态',
`user_id` int(11) DEFAULT '0' NOT NULL comment '用户ID',
`create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
`create_by` int(11) DEFAULT '1' NOT NULL comment '创建用户ID',
`update_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
PRIMARY KEY (owner_user_id))ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 comment '车主用户';

DROP TABLE IF EXISTS `business_user`;
CREATE TABLE `business_user`(business_user_id int(11) NOT NULL AUTO_INCREMENT COMMENT '商家用户ID',
`business_name` varchar(64) NOT NULL comment '商家姓名',
`business_gender` varchar(64) comment '商家性别',
`mobile_phone_number` varchar(16) NOT NULL UNIQUE comment '手机号码',
`store_location` varchar(64) comment '门店位置',
`examine_state` varchar(16) DEFAULT '已通过' NOT NULL comment '审核状态',
`user_id` int(11) DEFAULT '0' NOT NULL comment '用户ID',
`create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
`create_by` int(11) DEFAULT '1' NOT NULL comment '创建用户ID',
`update_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
PRIMARY KEY (business_user_id))ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 comment '商家用户';

DROP TABLE IF EXISTS `financial_user`;
CREATE TABLE `financial_user`(financial_user_id int(11) NOT NULL AUTO_INCREMENT COMMENT '财务用户ID',
`employee_work_number` varchar(64) NOT NULL UNIQUE comment '员工工号',
`employee_name` varchar(64) comment '员工姓名',
`financial_gender` varchar(64) comment '员工性别',
`contact_number` varchar(16) comment '联系号码',
`two_dimensional_code` varchar(255) comment '二维码',
`examine_state` varchar(16) DEFAULT '已通过' NOT NULL comment '审核状态',
`user_id` int(11) DEFAULT '0' NOT NULL comment '用户ID',
`create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
