DROP TABLE IF EXISTS `employee_performance`;
CREATE TABLE `employee_performance`(employee_performance_id int(11) NOT NULL AUTO_INCREMENT COMMENT '员工绩效ID',
`performance_title` varchar(64) comment '绩效标题',
`employee_name` varchar(64) comment '员工姓名',
`evaluation_time` datetime comment '评估时间',
`service_singular` double(8,2) DEFAULT 0 comment '服务单数',
`quality_of_service` varchar(64) comment '服务质量',
`working_attitude` varchar(64) comment '工作态度',
`performance_level` varchar(64) comment '绩效等级',
`assessment_results` varchar(64) comment '评估结果',
`work_suggestion` text comment '工作建议',
`create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
`create_by` int(11) DEFAULT '1' NOT NULL comment '创建用户ID',
`update_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
PRIMARY KEY (employee_performance_id))ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 comment '员工绩效';

