insert into `notice` values ('1','系统维护通知','<p>网站升级通知</p><p>尊敬的客户，为了提供更好的用户体验，我们将于本周三凌晨1:00-5:00进行系统维护升级，期间可能出现短暂服务中断。建议您提前保存操作数据，感谢您的理解与支持！</p>','2026-01-23 09:53:15','2026-01-23 09:53:15');
insert into `notice` values ('2','新功能上线','<p>搜索功能已优化升级！现已正式开放使用，支持关键词搜索，快去体验检索服务吧~</p>','2026-01-23 09:53:15','2026-01-23 09:53:15');
insert into `notice` values ('3','客服时间调整','<p>人工客服服务时间已延长为每日8:00-22:00（含节假日），智能客服24小时在线，随时为您解答问题。</p>','2026-01-23 09:53:15','2026-01-23 09:53:15');
insert into `notice` values ('4','规范提示','<p>请遵守《用户行为守则》：禁止发布广告、虚假信息及不当内容。共同维护友善的网络环境，违规账号将受到限制。</p>','2026-01-23 09:53:15','2026-01-23 09:53:15');
