insert into `forum` values ('1','100','1','小明','1','150','测试内容1','关键字1','描述','#','新手求助|入门指南 |经验分享','/upload/forum_1.jpg','<p>大家好!我是新来的，刚注册不久，对这个平台还不太熟悉。感觉这里氛围挺好的，希望能和大家多多交流学习。有没有前辈可以指点一下，哪些版块比较活跃，或者有什么需要注意的地方吗?期待认识各位朋友!</p>','2026-01-23 09:53:15','2026-01-23 09:53:15','','分类二','0');
insert into `forum` values ('2','100','2','小明','0','30','测试内容2','关键字2','dec','#','新鲜发现|生活分享|交流讨论','/upload/forum_2.jpg','<p>大家最近有发现什么让你眼前一亮的新事物吗？</p><p>不管是线上还是线下，最近有没有遇到让你觉得"这个真不错！"的事物？可以是APP、服务方式、小工具或者任何有趣的发现。来分享一下你的见闻吧！好的坏的都可以说说，也许能帮助改进呢。</p>','2026-01-23 09:53:15','2026-01-23 09:53:15','','分类一','0');
insert into `forum` values ('3','100','2','小红','0','42','测试内容3','关键字3','dec2','#','求助|入门指南|经验分享','/upload/forum_3.jpg','<p>刚接触一个新领域，大家有什么建议吗？</p><p>最近刚接触一个新领域而且很感兴趣，但完全不知道从哪开始。有经验的朋友能分享一下入门必备知识吗？比如需要准备什么？有哪些常见误区要避免？感谢指点！</p>','2026-01-23 09:53:15','2026-01-23 09:53:15','','分类二','0');
insert into `forum` values ('4','100','2','小红','0','22','测试内容4','关键字4','dec3','#','用户习惯|时间管理|社区互动','/upload/forum_4.jpg','<p>你认为自己通常什么时候最活跃？</p><p>A. 早晨（6-10点）</p><p>B. 午间（11-14点）</p><p>C. 下午（15-18点）</p><p>D. 晚间（19-23点）</p><p>E. 深夜（0-5点）</p><p>欢迎留言说明你的选择理由！</p>','2026-01-23 09:53:15','2026-01-23 09:53:15','','分类三','0');
